,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    m.MEMBER_ID,',
'    m.JOIN_DATE,',
'    m.ADDRESS_ID,',
'    m.DATE_OF_BIRTH,',
'    ',
'    p.PACKAGE_ID,',
'    p.PACKAGE_NAME,',
'    p.COST,',
'    p.DISCOUNT,',
'    p.DURATION,',
'    p.START_DATE,',
'    p.END_DATE,',
'    ',
'    pay.PAYMENT_ID,',
'    pay.AMOUNT,',
'    pay.PAYMENTDATE,',
'    pay.PAYMENTMETHOD',
'',
'FROM ',
'    MEMBERS m',
'JOIN ',
'    PAYMENT pay ON m.MEMBER_ID = pay.MEMBER_ID',
'JOIN ',
'    PACKAGE p ON pay.PACKAGE_ID = p.PACKAGE_ID',
