'JOIN ',
'    MEMBERS M ON AR.MEMBER_ID = M.MEMBER_ID',
'JOIN ',
'    USERS U ON M.MEMBER_ID = U.USER_ID',
'WHERE ',
'    TRIM(AR.ABSENCE) = ''Absent''',
'GROUP BY ',
'    M.MEMBER_ID, U.USER_NAME',
'HAVING ',
'    COUNT(*) > 3;',
''))
